import{_ as i}from"./chunks/skills.CFndjk6_.js";import{_ as a,c as s,o as l,a1 as t}from"./chunks/framework.DDNAyvCW.js";const g=JSON.parse('{"title":"Skills Usage Guide","description":"","frontmatter":{},"headers":[],"relativePath":"docs/skills/usage/index.md","filePath":"docs/skills/usage/index.md"}'),n={name:"docs/skills/usage/index.md"};function o(r,e,h,p,d,c){return l(),s("div",null,e[0]||(e[0]=[t('<h1 id="skills-usage-guide" tabindex="-1">Skills Usage Guide <a class="header-anchor" href="#skills-usage-guide" aria-label="Permalink to &quot;Skills Usage Guide&quot;">​</a></h1><h2 id="what-are-skills" tabindex="-1">What Are Skills? <a class="header-anchor" href="#what-are-skills" aria-label="Permalink to &quot;What Are Skills?&quot;">​</a></h2><p>Skills let you turn common workflows, best practices, and domain knowledge into reusable instruction sets. Each Skill is an independent, executable “skill package” that is automatically injected into the AI system prompts, so the AI can follow the way <em>you</em> want tasks to be done.</p><p><img src="'+i+`" alt=""></p><h3 id="from-general-assistant-to-domain-expert" tabindex="-1">From “General Assistant” to “Domain Expert” <a class="header-anchor" href="#from-general-assistant-to-domain-expert" aria-label="Permalink to &quot;From “General Assistant” to “Domain Expert”&quot;">​</a></h3><p>Imagine you are a Kubernetes SRE. Whenever a Pod is unhealthy, you typically:</p><ol><li>Check Pod status.</li><li>Inspect logs.</li><li>Analyze resource usage.</li><li>Apply a fix.</li></ol><p>Previously, you had to run these commands manually in Chaterm or rely on the AI’s generic knowledge. Now, you can create or import a <strong>Kubernetes Pod troubleshooting Skill</strong>, and the AI will automatically follow your Skill’s end‑to‑end procedure — as if you had personally trained it.</p><h2 id="key-capabilities" tabindex="-1">Key Capabilities <a class="header-anchor" href="#key-capabilities" aria-label="Permalink to &quot;Key Capabilities&quot;">​</a></h2><h3 id="reusable-instruction-sets" tabindex="-1">Reusable instruction sets <a class="header-anchor" href="#reusable-instruction-sets" aria-label="Permalink to &quot;Reusable instruction sets&quot;">​</a></h3><p>Each Skill is a standalone, reusable instruction set. Once created, it can be applied across multiple scenarios without rewriting the same steps.</p><h3 id="automatically-injected-into-context" tabindex="-1">Automatically injected into context <a class="header-anchor" href="#automatically-injected-into-context" aria-label="Permalink to &quot;Automatically injected into context&quot;">​</a></h3><p>Enabled Skills are automatically added to the AI system prompts. You don’t need to call them manually. When you describe a relevant scenario, the AI will recognize it and apply the appropriate Skill.</p><h3 id="resource-files-support" tabindex="-1">Resource files support <a class="header-anchor" href="#resource-files-support" aria-label="Permalink to &quot;Resource files support&quot;">​</a></h3><p>A Skill can include scripts, templates, configuration files, and other resources. This makes Skills more than plain text — they can carry executable code and configs.</p><h3 id="team-sharing" tabindex="-1">Team sharing <a class="header-anchor" href="#team-sharing" aria-label="Permalink to &quot;Team sharing&quot;">​</a></h3><p>Created Skills can be shared within your team to standardize workflows, ensuring everyone follows the same best practices.</p><h2 id="get-started" tabindex="-1">Get Started <a class="header-anchor" href="#get-started" aria-label="Permalink to &quot;Get Started&quot;">​</a></h2><h3 id="where-to-find-skills" tabindex="-1">Where to find Skills <a class="header-anchor" href="#where-to-find-skills" aria-label="Permalink to &quot;Where to find Skills&quot;">​</a></h3><ul><li><strong>Terminal Skills official repository</strong><ul><li><a href="https://github.com/chaterm/terminal-skills" target="_blank" rel="noreferrer">chaterm/terminal-skills</a> – A curated collection of Skills designed for terminal workflows.</li></ul></li><li><strong>Community contributions</strong><ul><li>Search for <code>terminal-skills</code> on GitHub to discover more community‑maintained Skills.</li></ul></li></ul><h3 id="create-a-skill-in-chaterm" tabindex="-1">Create a Skill in Chaterm <a class="header-anchor" href="#create-a-skill-in-chaterm" aria-label="Permalink to &quot;Create a Skill in Chaterm&quot;">​</a></h3><ol><li>Open the <strong>Settings</strong> page in Chaterm.</li><li>Go to the <code>Skills</code> tab and click <strong>Create Skill</strong> or <strong>Import</strong>.</li><li>Fill in the basic Skill information: <ul><li><strong>Name</strong>: Display name of the Skill.</li><li><strong>Description</strong>: When to use this Skill and what it does.</li><li><strong>Content</strong>: Detailed workflow and instructions.</li><li><strong>Resource files</strong> (optional): Related scripts, templates, and other files.</li></ul></li><li>Click <strong>Save</strong>. The Skill is enabled automatically and injected into the AI context.</li></ol><h3 id="skill-format-example" tabindex="-1">Skill format example <a class="header-anchor" href="#skill-format-example" aria-label="Permalink to &quot;Skill format example&quot;">​</a></h3><p>Here is an example Skill for Kubernetes Pod troubleshooting:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># Kubernetes Pod Troubleshooting</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Description</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Automatically run a complete troubleshooting workflow when a user reports an unhealthy Pod.</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Steps</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">1.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Check Pod status and events</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">   -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Run </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\`kubectl get pod &lt;pod-name&gt; -n &lt;namespace&gt; -o yaml\`</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">   -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Review events from </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\`kubectl describe pod &lt;pod-name&gt; -n &lt;namespace&gt;\`</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">2.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Inspect the last 100 lines of logs</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">   -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Run </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\`kubectl logs &lt;pod-name&gt; -n &lt;namespace&gt; --tail=100\`</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">3.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Analyze resource usage</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">   -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Check CPU and memory: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\`kubectl top pod &lt;pod-name&gt; -n &lt;namespace&gt;\`</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">   -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Review resource limits: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\`kubectl get pod &lt;pod-name&gt; -n &lt;namespace&gt; -o jsonpath=&#39;{.spec.containers[*].resources}&#39;\`</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">4.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Provide remediation suggestions</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">   -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Based on the findings, provide targeted recommendations.</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">   -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> If resources are insufficient, suggest adjusting resource limits.</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">   -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> If configuration is incorrect, provide corrected configuration examples.</span></span></code></pre></div><h2 id="skill-structure" tabindex="-1">Skill Structure <a class="header-anchor" href="#skill-structure" aria-label="Permalink to &quot;Skill Structure&quot;">​</a></h2><h3 id="basic-structure" tabindex="-1">Basic structure <a class="header-anchor" href="#basic-structure" aria-label="Permalink to &quot;Basic structure&quot;">​</a></h3><p>A complete Skill typically contains:</p><ol><li><strong>Title</strong>: Name of the Skill.</li><li><strong>Description</strong>: Purpose, scenarios, and expected outcomes.</li><li><strong>Steps</strong>: Detailed workflow, which can include: <ul><li>Command examples.</li><li>Checkpoints.</li><li>Decision points.</li><li>Error handling.</li></ul></li></ol><h3 id="advanced-features" tabindex="-1">Advanced features <a class="header-anchor" href="#advanced-features" aria-label="Permalink to &quot;Advanced features&quot;">​</a></h3><h4 id="conditional-logic" tabindex="-1">Conditional logic <a class="header-anchor" href="#conditional-logic" aria-label="Permalink to &quot;Conditional logic&quot;">​</a></h4><p>Skills can include simple conditional logic:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Steps</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">1.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Check service status.</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">2.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> If status is failed:</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">   -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Inspect error logs.</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">   -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Attempt to restart the service.</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">3.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> If status is active:</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">   -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Verify the service is functioning correctly.</span></span></code></pre></div><h4 id="referencing-resource-files" tabindex="-1">Referencing resource files <a class="header-anchor" href="#referencing-resource-files" aria-label="Permalink to &quot;Referencing resource files&quot;">​</a></h4><p>Skills can reference external resource files:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Resources</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> scripts/deploy.sh</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> templates/config.yaml</span></span></code></pre></div><h2 id="using-skills" tabindex="-1">Using Skills <a class="header-anchor" href="#using-skills" aria-label="Permalink to &quot;Using Skills&quot;">​</a></h2><h3 id="enable-or-disable-a-skill" tabindex="-1">Enable or disable a Skill <a class="header-anchor" href="#enable-or-disable-a-skill" aria-label="Permalink to &quot;Enable or disable a Skill&quot;">​</a></h3><p>In the Skills management page, you can:</p><ul><li><strong>Enable a Skill</strong>: Toggle it on to immediately inject it into the AI context.</li><li><strong>Disable a Skill</strong>: Toggle it off to prevent the AI from using it.</li><li><strong>Edit a Skill</strong>: Update its content and configuration.</li><li><strong>Delete a Skill</strong>: Remove Skills you no longer need.</li></ul><h3 id="use-skills-in-conversations" tabindex="-1">Use Skills in conversations <a class="header-anchor" href="#use-skills-in-conversations" aria-label="Permalink to &quot;Use Skills in conversations&quot;">​</a></h3><p>Once a Skill is enabled, simply describe your request in natural language and the AI will automatically apply the right Skill.</p><p><strong>Example conversation</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You: This Pod looks unhealthy, help me troubleshoot it.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>AI: [Automatically using the Kubernetes Pod Troubleshooting Skill]</span></span>
<span class="line"><span>    - Checking Pod status...</span></span>
<span class="line"><span>    - Inspecting logs...</span></span>
<span class="line"><span>    - Analyzing resource usage...</span></span>
<span class="line"><span>    - Providing remediation suggestions...</span></span></code></pre></div><h3 id="multiple-skills-working-together" tabindex="-1">Multiple Skills working together <a class="header-anchor" href="#multiple-skills-working-together" aria-label="Permalink to &quot;Multiple Skills working together&quot;">​</a></h3><p>You can enable multiple Skills at the same time. The AI will pick and combine Skills intelligently based on the conversation:</p><ul><li>When several Skills match, the AI can use them together.</li><li>Skills can complement each other to form end‑to‑end solutions.</li></ul><h2 id="real‐world-use-cases" tabindex="-1">Real‑World Use Cases <a class="header-anchor" href="#real‐world-use-cases" aria-label="Permalink to &quot;Real‑World Use Cases&quot;">​</a></h2><h3 id="enterprise-standardization" tabindex="-1">Enterprise standardization <a class="header-anchor" href="#enterprise-standardization" aria-label="Permalink to &quot;Enterprise standardization&quot;">​</a></h3><p>For enterprise users, Skills provide:</p><h4 id="standardized-workflows" tabindex="-1">Standardized workflows <a class="header-anchor" href="#standardized-workflows" aria-label="Permalink to &quot;Standardized workflows&quot;">​</a></h4><p>Turn best practices into Skills to ensure consistent operations across the team, for example:</p><ul><li><strong>Deployment Skill</strong>: Standardized application deployment procedure.</li><li><strong>Rollback Skill</strong>: Unified rollback process.</li><li><strong>Security Check Skill</strong>: Standard security audit workflow.</li></ul><h4 id="lower-onboarding-cost" tabindex="-1">Lower onboarding cost <a class="header-anchor" href="#lower-onboarding-cost" aria-label="Permalink to &quot;Lower onboarding cost&quot;">​</a></h4><p>New team members can directly leverage existing Skills:</p><ul><li>No need to memorize complex commands and parameters.</li><li>No need to fully understand every implementation detail.</li><li>They only need to describe the goal; the AI handles the workflow.</li></ul><h4 id="knowledge-capture" tabindex="-1">Knowledge capture <a class="header-anchor" href="#knowledge-capture" aria-label="Permalink to &quot;Knowledge capture&quot;">​</a></h4><p>Convert senior engineers’ experience into executable Skills:</p><ul><li>Troubleshooting know‑how → Troubleshooting Skills.</li><li>Performance tuning techniques → Performance optimization Skills.</li><li>Hardening practices → Security Skills.</li></ul><h3 id="personal-productivity" tabindex="-1">Personal productivity <a class="header-anchor" href="#personal-productivity" aria-label="Permalink to &quot;Personal productivity&quot;">​</a></h3><p>For individual users, Skills help you:</p><ul><li><strong>Automate repetitive tasks</strong>: Turn frequent workflows into Skills.</li><li><strong>Extend AI capabilities</strong>: Inject your domain expertise into the AI.</li><li><strong>Respond faster</strong>: Let the AI execute complex multi‑step workflows quickly.</li></ul><h2 id="import-and-export" tabindex="-1">Import and Export <a class="header-anchor" href="#import-and-export" aria-label="Permalink to &quot;Import and Export&quot;">​</a></h2><h3 id="import-skills" tabindex="-1">Import Skills <a class="header-anchor" href="#import-skills" aria-label="Permalink to &quot;Import Skills&quot;">​</a></h3><p>You can import Skills from:</p><ol><li><p><strong>Local files</strong></p><ul><li>Markdown <code>SKILL.md</code> files.</li><li>ZIP Skill bundles that include resource files.</li></ul></li><li><p><strong>Terminal Skills repository</strong></p><ul><li>Go to <a href="https://github.com/chaterm/terminal-skills" target="_blank" rel="noreferrer">chaterm/terminal-skills</a>.</li><li>Pick the Skills you need and copy their folders into the Chaterm <code>skills</code> directory.</li></ul></li></ol><h2 id="related-resources" tabindex="-1">Related Resources <a class="header-anchor" href="#related-resources" aria-label="Permalink to &quot;Related Resources&quot;">​</a></h2><h3 id="terminal-skills-official-repository" tabindex="-1">Terminal Skills official repository <a class="header-anchor" href="#terminal-skills-official-repository" aria-label="Permalink to &quot;Terminal Skills official repository&quot;">​</a></h3><ul><li><strong>GitHub</strong>: <a href="https://github.com/chaterm/terminal-skills" target="_blank" rel="noreferrer">chaterm/terminal-skills</a></li><li><strong>Description</strong>: A curated collection of terminal‑focused Skills covering various ops and development scenarios.</li></ul><h2 id="what-to-read-next" tabindex="-1">What to Read Next <a class="header-anchor" href="#what-to-read-next" aria-label="Permalink to &quot;What to Read Next&quot;">​</a></h2><ul><li>For troubleshooting and best practices, see <strong><a href="./../troubleshooting/">Skills Troubleshooting &amp; Best Practices</a></strong>.</li><li>To learn about the settings UI, see <strong><a href="/docs/settings/skills/">Skills Settings</a></strong>.</li></ul>`,71)]))}const m=a(n,[["render",o]]);export{g as __pageData,m as default};
